<template>
    <div class="about">
        <nav v-if="device!='mobile'" class="navbar" id="aboutNav" :class="{'navbar-fixed': isFixed }">
            <div class="container">
                <div class="nav-logo">
                    <router-link to="/">LOGO</router-link>
                </div>
                <div class="nav-right">
                    <ul class="nav-list flex">
                        <li class="item"
                            v-for="(item, index) in aboutNavs" 
                            :key="index" 
                            :class="{active: active===index}" 
                            @click="scrollTo(index)">
                            <a>{{ item }}</a>
                        </li>
                    </ul>
                </div>
            </div>
        </nav>

        <div class="about-content">
            <!-- 基本资料 -->
            <div class="info">
                <div class="wrapper">
                    <h1 class="header__title">
                        <a>Jawen 的个人博客</a>
                    </h1>
                    <h2 class="header__desc">精通手撕快递的前端攻城狮</h2>
                </div>
            </div>

            <!-- 项目经验 -->
            <div class="project">
                <div class="container">
                    <div class="title">项目经验</div>
                    <div class="project-content flex">
                        <div class="flex-item" v-for="(item, index) in project" :key="index">
                            <div class="project-item">
                                <a href="#" target="_blank">
                                    <div class="hover-bg">
                                        <div class="hover-text">
                                            <h4>{{ item.title }}</h4>
                                            <p>{{ item.desc }}</p>
                                            <div class="clearfix"></div>
                                        </div>
                                        <img class="responsive" :src="`/static/images/screenshots/${item.src}`" :alt="item.title">
                                    </div>
                                </a>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <!-- 专业技能 -->
            <div class="skills">
                <div class="container">
                    <div class="title">专业技能</div>
                    <div class="skills-content flex">
                        <div class="skills-chart flex">
                            <div class="chart-item block" v-for="(item, index) in skills" :key="index">
                                <div class="circle" :style="{background: `${item.color}`}">
                                    <div class="pie pie-right">
                                        <div class="right"></div>
                                    </div>
                                    <div class="pie pie-left">
                                        <div class="left" :style="{transform: `rotate(${item.value*3.6 - 180}deg)`}"></div>
                                    </div>
                                    <div class="mask" :style="{color: `${item.color}`}">
                                        <span>{{item.name}}</span>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <!-- 词云 -->
                        <div class="cloud">
                            <wordCloud class="cloud-content"></wordCloud>
                        </div>
                    </div>
                </div>
            </div>

            <!-- 工作经历 -->
            <div class="experience">
                <div class="container">
                    <div class="title">工作经历</div>
                    <div class="wrapper flex">
                        <div class="flex-item">
                            <div class="card">
                                <div class="content">
                                    <img class="resource" src="https://gw.alipayobjects.com/mdn/rms_f8c6a0/afts/img/A*icqYSbEiNxIAAAAAAAAAAABkARQnAQ" alt="resource">
                                    <p class="title">广州市XXX科技有限公司</p>
                                    <p class="desc">主要担任该公司的前端职位，开发和维护公司的项目。</p>
                                    <a class="detail" href="https://antv-2018.alipay.com/zh-cn/vis/chart/index.html" target="newtab">查看详情</a>
                                </div>
                            </div>
                        </div>
                        <div class="flex-item">
                            <div class="card">
                                <div class="content">
                                    <img class="resource" src="https://gw.alipayobjects.com/mdn/rms_f8c6a0/afts/img/A*mt47RKxGy8kAAAAAAAAAAABkARQnAQ" alt="resource">
                                    <p class="title">广州市XXX科技有限公司</p>
                                    <p class="desc">主要担任该公司的前端职位，开发和维护公司的项目。</p>
                                    <a class="detail" href="https://antv-2018.alipay.com/zh-cn/vis/chart/index.html" target="newtab">查看详情</a>
                                </div>
                            </div>
                        </div>
                        <div class="flex-item">
                            <div class="card">
                                <div class="content">
                                    <img class="resource" src="https://gw.alipayobjects.com/mdn/rms_f8c6a0/afts/img/A*zBDKTaSg-7AAAAAAAAAAAABkARQnAQ" alt="resource">
                                    <p class="title">广州市XXX科技有限公司</p>
                                    <p class="desc">主要担任该公司的前端职位，开发和维护公司的项目。</p>
                                    <a class="detail" href="https://antv-2018.alipay.com/zh-cn/vis/chart/index.html" target="newtab">查看详情</a>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <!-- 自我评价 -->
            <div class="evaluate">
                <div class="container">
                    <div class="title">自我评价</div>
                    <div style="height: 200px;">
                        自我评价
                    </div>
                </div>
            </div>

            <!-- 联系方式 -->
            <div class="contact">
                <div class="container">
                    <div class="title">联系方式</div>
                    <!--  v-if="device!='mobile'" -->
                    <div class="about-map">
                        <iframe class="iframe" src="/static/partials/map.html"></iframe>
                    </div>
                </div>
                
            </div>
        </div>
        
    </div>
</template>
<script>
import { mapState } from 'vuex';
import { project } from '@/core/data';
import wordCloud from './wordCloud';
export default {
    data() {
        return {
            active: 0,
            aboutNavs: ['基本资料', '项目经验', '专业技能', '工作经历', '自我评价', '联系方式'],
            skills: [{
                name: 'vue',
                value: 82,
                color: '#41b883'
            },{
                name: 'electron',
                value: 75,
                color: '#32323e'
            },{
                name: 'wechat',
                value: 82,
                color: '#00bc0d'
            },{
                name: 'echart',
                value: 80,
                color: '#aa344c'
            },{
                name: 'elementUI',
                value: 85,
                color: '#409eff'
            },{
                name: 'sass',
                value: 73,
                color: '#e93f79'
            }],
            project,
            isFixed: false,
            offsetTop: 0
        }
    },
    components: {
        wordCloud
    },
    computed: {
        ...mapState({
            device: state => state.app.device
        })
    },
    mounted() {
        if(this.device != 'mobile'){
            window.addEventListener('scroll', this.onScroll);
            this.$nextTick(() => {
                this.offsetTop = document.querySelector('#aboutNav').offsetTop;
            })
        }
    },
    destroy() {
        if(this.device != 'mobile'){
            window.removeEventListener('scroll', this.onScroll);
        }
    },
    methods: {
        // 滚动监听
        onScroll() {
            // 设置或获取位于对象最顶端和窗口中可见内容的最顶端之间的距离 (被卷曲的高度)
            const scrollTop = window.pageYOffset || document.documentElement.scrollTop || document.body.scrollTop
            //如果被卷曲的高度大于吸顶元素到顶端位置 的距离
            this.isFixed = scrollTop > this.offsetTop+40 ? true : false;

            const navContents = document.querySelectorAll('.about-content>div');
            const offsetTopArr = []
            navContents.forEach(item => {
                offsetTopArr.push(item.offsetTop)
            })
            
            // const scrollTop = document.documentElement.scrollTop || document.body.scrollTop
            // 定义当前点亮的导航下标
            let navIndex = 0
            for (let n = 0; n < offsetTopArr.length; n++) {
                // 如果 scrollTop 大于等于第 n 个元素的 offsetTop 则说明 n-1 的内容已经完全不可见
                // 那么此时导航索引就应该是 n 了
                if (scrollTop >= offsetTopArr[n]) {
                    navIndex = n
                }
            }
            this.active = navIndex
        },
        // 滚动到指定元素位置
        scrollTo(index) {
            // 获取目标的 offsetTop
            // css选择器是从 1 开始计数，我们是从 0 开始，所以要 +1
            const targetOffsetTop = document.querySelector(`.about-content>div:nth-child(${index + 1})`).offsetTop
            
            let scrollTop = document.documentElement.scrollTop || document.body.scrollTop
            // 定义一次跳 50 个像素，数字越大跳得越快，但是会有掉帧得感觉
            const STEP = 50
            // 判断是往下滑还是往上滑
            if (scrollTop > targetOffsetTop) {
                // 往上滑
                smoothUp()
            } else {
                // 往下滑
                smoothDown()
            }

            // 定义往下滑函数
            function smoothDown() {
                // 如果当前 scrollTop 小于 targetOffsetTop 说明视口还没滑到指定位置
                if (scrollTop < targetOffsetTop) {
                    // 如果和目标相差距离大于等于 STEP 就跳 STEP
                    // 否则直接跳到目标点，目标是为了防止跳过了。
                    if (targetOffsetTop - scrollTop >= STEP) {
                        scrollTop += STEP
                    } else {
                        scrollTop = targetOffsetTop
                    }
                    document.body.scrollTop = scrollTop
                    document.documentElement.scrollTop = scrollTop
                    // 在这种场景下，requestAnimationFrame 相比 setInterval 性价比更高
                    requestAnimationFrame(smoothDown)
                }
            }

            // 定义往上滑函数
            function smoothUp() {
                if (scrollTop > targetOffsetTop) {
                    if (scrollTop - targetOffsetTop >= STEP) {
                        scrollTop -= STEP
                    } else {
                        scrollTop = targetOffsetTop
                    }
                    document.body.scrollTop = scrollTop
                    document.documentElement.scrollTop = scrollTop
                    requestAnimationFrame(smoothUp)
                }
            }
        }
    }
}
</script>
<style lang="scss" scoped>
.about{
    .container{
        .title{
            text-align: center;
            font-weight: 400;
            font-size: $font_large;
            margin-bottom: 30px;
            @include font_color($font-color-light);
        }
    }

    .about-content{
        position: relative;
        @include bg_color($background-color-light);

        // 个人资料
        .info{
            height: calc(100vh - 90px);
            width: 100%;
            background: url('../../../static/images/img/header-bg.jpg') no-repeat 50%;
            background-size: cover;
            .wrapper{
                position: relative;
                align-items: center;
                height: calc(100vh - 90px);
                display: flex;
                justify-content: center;
                -webkit-box-orient: vertical;
                -webkit-box-direction: normal;
                flex-direction: column;
                z-index: 1;
                .header__title{
                    letter-spacing: -1px;
                    font-weight: 700;
                    font-size: 50px;
                    text-shadow: 0 3px 6px rgba(0,0,0,.3);
                    animation: fade-in-down 1s both;
                    animation-delay: .3s;
                    a{
                        cursor: pointer;
                        color: #fff;
                        &:hover{
                            color: hsla(0,0%,100%,.8);
                        }
                    }
                }
                .header__desc{
                    font-size: 20px;
                    font-weight: 400;
                    margin-top: 10px;
                    color: hsla(0,0%,100%,.8);
                    line-height: 24px;
                    text-align: center;
                    text-shadow: 0 3px 6px rgba(0,0,0,.3);
                    animation: fade-in-down .9s both;
                    animation-delay: .5s;
                }
            }
        }

        // 项目经验
        .project{
            position: relative;
            margin-top: 100px;
            .container{
                .project-content{
                    position: relative;
                    overflow: hidden;
                    flex-flow: row wrap;
                    .flex-item{
                        width: 25%;
                        padding-right: 15px;
                        padding-left: 15px;
                        backface-visibility: hidden;
                        transition-property: transform, opacity;
                        transform: translate3d(0px, 0px, 0px);
                        transition-duration: 0.8s;
                        .project-item{
                            margin-bottom: 30px;
                            transition: all 0.5s ease-out;
                            a{
                                cursor: pointer;
                                @include font_color($font-color-light);
                            }
                            &:hover{
                                transform: scale(1.2);
                            }
                            .hover-bg{
                                position: relative;
                                height: 152px;
                                overflow: hidden;
                                .hover-text{
                                    position: absolute;
                                    text-align: center;
                                    margin: 0 auto;
                                    background: rgba(0, 0, 0, 0.66);
                                    padding: 17% 0;
                                    height: 100%;
                                    width: 100%;
                                    opacity: 0;
                                    transition: all 0.5s;
                                    h4{
                                        opacity: 0;
                                        color: #fff;
                                        transform: translateY(100%);
                                        transition: all 0.3s;
                                    }
                                    p{
                                        opacity: 0;
                                        color: #fff;
                                        transform: translateY(0);
                                        transition: all 0.3s;
                                        font-size: $font_medium_s;
                                    }
                                }
                                &:hover{
                                    .hover-text{
                                        opacity: 1;
                                        h4{
                                            opacity: 1;
                                            transform: translateY(0);
                                        }
                                        p{
                                            opacity: 1;
                                            transform: translateY(100%);
                                        }
                                    }
                                }
                                img{
                                    display: block;
                                    max-width: 100%;
                                    height: auto;
                                }
                            }
                        }
                    }
                }
            }
        }

        // 专业技能
        .skills{
            margin: 100px auto;
            .container{
                .skills-content{
                    justify-content: space-between;
                    flex-flow: row wrap;
                    .skills-chart{
                        width: 60%;
                        flex-flow: row wrap;
                        justify-content: space-between;
                        .chart-item{
                            position: relative;
                            width: 200px;
                            height: 200px;
                            margin-bottom: 15px;
                            .circle {
                                position: absolute;
                                top: 0;
                                right: 0;
                                bottom: 0;
                                left: 0;
                                margin: auto;
                                height: 120px;
                                width: 120px;
                                border-radius: 50%;
                            }
                            .pie-right, .pie-left { 
                                position: absolute;
                                top: 0;
                                left: 0;
                                height: 120px;
                                width: 120px;
                                border-radius: 50%;
                            }
                            .right, .left {
                                position: absolute;
                                top: 0;
                                left: 0;
                                height: 120px;
                                width: 120px;
                                border-radius: 50%;
                                background: #cccccc;
                                transition: all .3s;
                            }
                            .pie-right, .right { 
                                clip: rect(0, auto, auto, 60px);
                                transition: all .3s;
                            }
                            .pie-left, .left { 
                                clip: rect(0, 60px, auto, 0);
                                transition: all .3s;
                            }
                            .right{
                                transform: rotate(180deg);
                            }
                            .mask {
                                position: absolute;
                                top: 20px;
                                left: 20px;
                                height: 80px;
                                width: 80px;
                                line-height: 80px;
                                @include bg_color($background-color-light);
                                border-radius: 50%;
                                text-align: center;
                            }
                        }
                    }
                }
            }
        }

        // 工作经历
        .experience{
            position: relative;
            margin: auto;
            background-color: #fafbfd;
            .container{
                height: 100%;
                padding-bottom: 150px;
                .title{
                    padding-top: 30px;
                }
                .wrapper{
                    position: relative;
                    width: 100%;
                    z-index: 1;
                    margin-top: 57px;
                    flex-flow: row wrap;
                    .flex-item{
                        width: 33.33%;
                        padding-left: 6px;
                        padding-right: 6px;
                        .card{
                            background-color: #fff;
                            margin-top: 0;
                            height: 400px;
                            transition: all .3s;
                            box-shadow: 0 8px 10px rgba(49,70,89,.05);
                            .content{
                                text-align: center;
                                padding: 69px 10% 96px;
                                .resource{
                                    transition: all .3s;
                                    height: 96px;
                                }
                                .title{
                                    font-size: 1.71em;
                                    color: #000;
                                    margin-bottom: 0;
                                }
                                .desc{
                                    margin-top: 16px;
                                    opacity: .6;
                                    width: 100%;
                                    font-size: 1em;
                                    font-weight: 350;
                                    line-height: 1.7em;
                                    color: #697b8c;
                                }
                                .detail{
                                    margin-top: 14.2%;
                                    color: #4776e8;
                                    display: none;
                                    font-size: 1.14em;
                                }
                            }
                            &:hover{
                                margin-top: -25px;
                                height: 450px;
                                border-image: linear-gradient(90deg,#aa6aff,#706dff) 30 30;
                                border-bottom: 4px solid;
                                border-color: #aa6aff;
                                .detail{
                                    display: block;
                                }
                            }
                        }
                    }
                }
            }
        }

        // 自我评价
        .evaluate{
            .container{
                > .title{
                    text-align: center;
                    font-weight: 400;
                    font-size: $font_large;
                    margin-bottom: 30px;
                    padding-top: 100px;
                }
            }
        }

        // 联系方式
        .contact{
            height: 500px;
            .container{
                > .title{
                    text-align: center;
                    font-weight: 400;
                    font-size: $font_large;
                    margin-bottom: 30px;
                    padding-top: 100px;
                }
            }
            .about-map{
                background: $background-color-dark;
                padding: 5px 5px 2px;
                border-radius: 3px;
                .iframe{
                    border: none;
                    width: 100%;
                }
            }
        }
    }
}

@keyframes fade-in-down {
    0% {
        -webkit-transform: translate(0, 100px);
        transform: translate(0, 100px);
    }
    100% {
        opacity: 1;
        -webkit-transform: translate(0, 0);
        transform: translate(0, 0);
    }
}

@media screen and (max-width: 1200px){
    .about .container{
        width: 80% !important;
    }
    .project .flex-item{
        width: 50% !important;
    }
    .skills .skills-chart{
        width: 100% !important;
    }
}
@media screen and (max-width: 780px){
    .about .container{
        width: 95% !important;
    }
    .project .container .project-content .flex-item{
        width: 100% !important;
        margin: 0 auto 30px;
    }
    .project .container .project-content .flex-item .hover-bg{
        height: 200px !important;
    }
    .skills .container .skills-content .skills-chart{
        width: 100% !important;
        margin: 0 auto;
    }
    .skills .container .skills-content .skills-chart .chart-item{
        width: 48.2% !important;
    }
    .experience .container .wrapper{
        width: 80% !important;
        margin: 0 auto;
    }
    .experience .container .wrapper .flex-item{
        width: 100% !important;
        margin-bottom: 30px;
    }
}
@media screen and (max-width: 576px){
    .info, 
    .info .wrapper{
        height: calc(100vh - 40px) !important;
    }
    .header__title{
        font-size: 38px !important;
    }
    .project{
        margin-top: 50px !important; 
    }
    .project .project-item{
        margin-bottom: 0 !important;
    }
    .experience .container{
        padding: 0 !important;
    }
    .cloud{
        width: 100%;
    }
    .cloud-content{
        margin: 0 auto;
    }
    .skills{
        margin: 50px auto !important; 
    }
}
</style>


